    Perform binary XOR on these inputs and return result also as a string.
    >>> string_xor('010', '110')
    '100'
    """
    result = []
    for c_a, c_b in zip(a, b):
        if c_a == '1' and c_b == '0':
            result.append('0')
        elif c_a == '0' and c_b == '1':
