            if num % i == 0:
                return False
        return True

    for i in range(2, int(n ** 0.5) + 1):
        if is_prime(i):
            count = 0
            while n % i == 0:
                count += 1
                n //= i
                if count == 1:
                    factors.append(i)
                    break
            if count > 1:
                factors.append(i)
                count = 0

    if n > 1:
        factors.append(n)

    return factors

