def combinations(*nums):
    """Generate all combinations of the given numbers."""
    if len(nums) == 0:
        yield []
        return

    n = len(nums)
    for i in range(n):
        for j in range(i, n):
            for k in range(j, n):
                yield nums[i], nums[j], nums[k]

