    rounded_avg(20, 33) => "0b11010"
    """
    if n > m:
        return -1

    total = n
    count = m - n + 1
    avg = total / count

    if avg < 0:
        return 0
    elif avg == int(avg):
        return "0b10"
    elif avg >= 1.0:
        return "0b1"
    elif avg >= 1.5:
        return "0b11"
    elif avg >= 2.0:
        return "0b111"
    elif avg >= 2.5:
        return "0b1111"
    else:
        return "0b11111"

